import React, { useState } from 'react';
import { FiCamera as Camera, FiCheckCircle as CheckCircle2, FiXCircle as XCircle, FiAlertTriangle as AlertTriangle } from 'react-icons/fi';
import { MdFingerprint as Fingerprint } from 'react-icons/md';

const ScanCheckin = ({ user }) => {
    const [scanning, setScanning] = useState(false);
    const [result, setResult] = useState(null); // 'success', 'error_location'
    const [locationInfo, setLocationInfo] = useState(null);

    const handleCheckIn = (scannedData) => {
        setScanning(true);
        setResult(null);

        setTimeout(() => {
            try {
                const data = JSON.parse(scannedData);
                if (data.type && data.name) {
                    // Update global live presence store
                    const presence = JSON.parse(localStorage.getItem('live_presence') || '{}');
                    presence[user.id] = {
                        type: data.type,
                        name: data.name,
                        checkInTime: new Date().toLocaleTimeString(),
                        facultyId: data.id,
                        floor: data.floor || 'Unknown',
                        bssid: data.bssid || 'N/A'
                    };
                    localStorage.setItem('live_presence', JSON.stringify(presence));

                    setLocationInfo(data);
                    setResult('success');
                } else {
                    setResult('error_location');
                }
            } catch (e) {
                setResult('error_location');
            }
            setScanning(false);
        }, 1200);
    };

    return (
        <div className="max-w-md mx-auto py-12 px-4">
            <div className="text-center mb-10">
                <h2 className="text-4xl font-extrabold text-white leading-tight">Location Monitoring</h2>
                <p className="text-gray-400 mt-4 text-sm font-medium">Verify your real-time presence using campus IoT infrastructure.</p>
            </div>

            <div className="bg-[#141417] rounded-[2.5rem] shadow-2xl border border-white/5 overflow-hidden relative">
                {/* Student Identity */}
                <div className="bg-white/5 px-8 py-6 flex items-center justify-between border-b border-white/5">
                    <div className="flex items-center space-x-4">
                        <div className="w-12 h-12 bg-blue-600 text-white rounded-2xl flex items-center justify-center font-black text-xl shadow-lg shadow-blue-900/40">{user.name.charAt(0)}</div>
                        <div>
                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-[0.2em]">{user.role}</p>
                            <p className="text-lg font-bold text-white leading-tight">{user.name}</p>
                        </div>
                    </div>
                </div>

                {/* Camera simulation area */}
                <div className="bg-gray-900 aspect-square relative flex items-center justify-center">
                    {scanning ? (
                        <div className="absolute inset-0 bg-[#0a0a0b]/90 flex flex-col items-center justify-center backdrop-blur-md z-10 transition-all">
                            <div className="w-20 h-20 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6 shadow-[0_0_30px_rgba(59,130,246,0.3)]"></div>
                            <p className="text-blue-400 font-black uppercase text-xs tracking-widest animate-pulse">Establishing handshake...</p>
                        </div>
                    ) : result === null ? (
                        <div className="text-center p-10">
                            <div className="w-64 h-64 border-2 border-dashed border-gray-800 rounded-[3rem] mb-10 flex items-center justify-center bg-white/5 relative group">
                                <Camera className="text-gray-700 group-hover:text-blue-500 transition-colors" size={56} />
                                <div className="absolute inset-0 border-2 border-blue-500/20 rounded-[3rem] animate-glow scale-110 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                            </div>
                            <p className="text-gray-500 text-xs mb-8 font-black uppercase tracking-widest">Awaiting Campus AP Signal</p>

                            <div className="grid grid-cols-2 gap-4">
                                <button
                                    onClick={() => handleCheckIn(JSON.stringify({ type: 'LAB', name: 'Computer Lab A1', id: 'LAB001', floor: 'Ground Floor', bssid: '3E:AA:D5:08:83:26' }))}
                                    className="py-4 px-4 bg-blue-600/10 text-blue-400 rounded-2xl text-[10px] font-black border border-blue-500/20 hover:bg-blue-600/20 transition-all uppercase tracking-widest shadow-xl"
                                >
                                    Mock Lab Scan
                                </button>
                                <button
                                    onClick={() => handleCheckIn(JSON.stringify({ type: 'CLASS', name: user.className || 'Theory Class B', id: 'ADV001', floor: '1st Floor', bssid: 'FA:80:19:52:03:43' }))}
                                    className="py-4 px-4 bg-emerald-600/10 text-emerald-400 rounded-2xl text-[10px] font-black border border-emerald-500/20 hover:bg-emerald-600/20 transition-all uppercase tracking-widest shadow-xl"
                                >
                                    Mock Class Scan
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-[#141417] absolute inset-0 flex flex-col items-center justify-center p-10 text-center animate-fade-in z-20">
                            {result === 'success' ? (
                                <>
                                    <div className="bg-blue-500/10 text-blue-500 rounded-[2rem] p-8 mb-8 border border-blue-500/20 shadow-[0_0_50px_rgba(59,130,246,0.1)]">
                                        <CheckCircle2 size={72} />
                                    </div>
                                    <h3 className="text-3xl font-black text-white mb-8 tracking-tight">Check-in Success</h3>
                                    <div className="w-full space-y-5 mb-10 text-left bg-white/5 p-8 rounded-3xl border border-white/5 shadow-inner">
                                        <div>
                                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">location</p>
                                            <p className="text-xl font-bold text-white italic">{locationInfo.type === 'LAB' ? 'Lab Resource' : 'Theory Classroom'}</p>
                                        </div>
                                        <div>
                                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">venue</p>
                                            <p className="text-xl font-bold text-white">{locationInfo.name}</p>
                                        </div>
                                        <div>
                                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">floor</p>
                                            <p className="text-xl font-bold text-white">{locationInfo.floor || 'N/A'}</p>
                                        </div>
                                        <div className="pt-4 border-t border-white/5">
                                            <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-2">Physical address</p>
                                            <p className="text-lg font-black text-emerald-400 uppercase tracking-tighter">
                                                {locationInfo.name} {locationInfo.floor}
                                            </p>
                                        </div>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <div className="bg-red-500/10 text-red-500 rounded-[2rem] p-8 mb-8 border border-red-500/20 shadow-[0_0_50px_rgba(239,68,68,0.1)]">
                                        <XCircle size={72} />
                                    </div>
                                    <h3 className="text-3xl font-black text-white mb-4">Auth Error</h3>
                                    <p className="text-gray-500 mb-10 text-base font-medium leading-relaxed">Invalid beacon signal or mismatched MAC signature. Please try again.</p>
                                </>
                            )}
                            <button
                                onClick={() => setResult(null)}
                                className="w-full py-5 bg-white text-black rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-gray-200 transition-all active:scale-95 shadow-2xl"
                            >
                                DISCARD & RESCAN
                            </button>
                        </div>
                    )}

                    {/* Overlay scanner frame */}
                    {result === null && !scanning && (
                        <div className="absolute inset-12 border-2 border-white/10 rounded-3xl pointer-events-none">
                            <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-blue-500 rounded-tl-3xl -ml-1 -mt-1"></div>
                            <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-blue-500 rounded-tr-3xl -mr-1 -mt-1"></div>
                            <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-blue-500 rounded-bl-3xl -ml-1 -mb-1"></div>
                            <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-blue-500 rounded-br-3xl -mr-1 -mb-1"></div>
                        </div>
                    )}
                </div>

                <div className="bg-white/5 p-8 flex items-start space-x-6 border-t border-white/5">
                    <Fingerprint className="text-blue-500 mt-1 shrink-0" size={32} />
                    <div>
                        <p className="text-sm text-white font-black uppercase tracking-[0.2em]">IoT Backbone Active</p>
                        <p className="text-xs text-gray-500 mt-2 leading-relaxed">
                            BSSID monitoring and Floor verification are enabled. Your precision location is mirrored to Faculty portals.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ScanCheckin;
